class Solution:
    def sumEvenGrandparent(self, root):
        def dfs(node, parent_val, grandparent_val):
            if not node:
                return 0
            total = 0
            if grandparent_val % 2 == 0:
                total += node.val
            total += dfs(node.left, node.val, parent_val)
            total += dfs(node.right, node.val, parent_val)
            return total
        return dfs(root, -1, -1)

