class Solution:
    def sumEvenGrandparent(self, root):
        def dfs(node, pval, gpval):
            if not node:
                return 0
            s = node.val if gpval % 2 == 0 and gpval >= 0 else 0
            return s + dfs(node.left, node.val, pval) + dfs(node.right, node.val, pval)
        return dfs(root, -1, -1)

